import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function ClientManagement(){

const [showForm,setShowForm] = useState(false);
const [clients,setClients] = useState([]);
const [projects,setProjects] = useState([]);
const [search,setSearch] = useState("");
const [editId,setEditId] = useState(null);

const [formData,setFormData] = useState({
name:"",
co_owner:"",
phone:"",
address:"",
project:"",
floor:"",
room:"",
amount_paid:"",
payment_mode:"",
bank_name:"",
cheque_no:"",
installments:[]
});

// ================= LOAD =================
const fetchClients = async ()=>{
try{
const res = await fetch("http://localhost:5000/api/clients");
const data = await res.json();
setClients(Array.isArray(data) ? data : data.clients || data.data || []);
}catch(err){ console.log(err); }
};

const fetchProjects = async ()=>{
try{
const res = await fetch("http://localhost:5000/api/projects");
const data = await res.json();
setProjects(Array.isArray(data) ? data : data.projects || data.data || []);
}catch(err){ console.log(err); }
};

useEffect(()=>{
fetchClients();
fetchProjects();
},[]);

// ================= PROJECT =================
const selectedProject = projects.find(
p => p.name === formData.project
);

// ================= ROOMS =================
const generateRooms = (floor)=>{
if(!floor || !selectedProject) return [];

let rooms=[];
const totalRooms = selectedProject.roomsPerFloor || 10;

for(let i=1;i<=totalRooms;i++){
rooms.push(`${floor}${i.toString().padStart(2,"0")}`);
}
return rooms;
};

// ================= HANDLE INPUT =================
const handleChange = (e)=>{
const {name,value} = e.target;

if(name==="name" || name==="co_owner"){
const valid = value.replace(/[^a-zA-Z\s]/g,"");
setFormData({...formData,[name]:valid});
return;
}

if(name==="bank_name"){
const valid = value.replace(/[^a-zA-Z\s]/g,"");
setFormData({...formData,bank_name:valid});
return;
}

if(name==="cheque_no"){
const numeric = value.replace(/\D/g,"");
setFormData({...formData,cheque_no:numeric});
return;
}

if(name==="address"){
const valid = value.replace(/[^a-zA-Z0-9\s]/g,"");
setFormData({...formData,address:valid});
return;
}

if(name==="phone"){
const numeric = value.replace(/\D/g,"");
if(numeric.length<=10){
setFormData({...formData,phone:numeric});
}
return;
}

if(name==="amount_paid"){
const num = Number(value);
if(num < 0) return;

if(num > 100000000){
alert("Amount cannot exceed 10 Cr");
return;
}
}

setFormData({...formData,[name]:value});
};

// ================= INSTALLMENTS =================
const addInstallment = ()=>{
setFormData({
...formData,
installments:[...formData.installments,{amount:"",date:""}]
});
};

const handleInstallmentChange = (index,field,value)=>{
const updated = [...formData.installments];

if(field==="amount"){
const num = Number(value);
if(num < 0) return;

if(num > 100000000){
alert("Installment cannot exceed 10 Cr");
return;
}
}

if(field==="date"){
if(index > 0){
const prevDate = updated[index-1].date;
if(prevDate && new Date(value) <= new Date(prevDate)){
alert("Date must be after previous installment");
return;
}
}

if(index < updated.length-1){
const nextDate = updated[index+1].date;
if(nextDate && new Date(value) >= new Date(nextDate)){
alert("Date must be before next installment");
return;
}
}
}

updated[index][field] = value;
setFormData({...formData,installments:updated});
};

// ================= SAVE =================
const handleSubmit = async ()=>{

if(!formData.name) return alert("Enter client name");
if(formData.phone.length!==10) return alert("Phone must be 10 digits");

const amount = Number(formData.amount_paid);
if(!amount || amount <= 0) return alert("Enter valid amount");
if(amount > 100000000) return alert("Amount cannot exceed 10 Cr");

for(let inst of formData.installments){
if(Number(inst.amount) > 100000000){
alert("Installment exceeds 10 Cr");
return;
}
}

for(let i=1;i<formData.installments.length;i++){
const prev = new Date(formData.installments[i-1].date);
const curr = new Date(formData.installments[i].date);
if(curr <= prev){
alert("Installments must be in increasing date order");
return;
}
}

if(!formData.project) return alert("Select project");
if(!formData.floor) return alert("Select floor");
if(!formData.room) return alert("Select room");

if(editId){
await fetch(`http://localhost:5000/api/clients/${editId}`,{
method:"PUT",
headers:{"Content-Type":"application/json"},
body:JSON.stringify(formData)
});
}else{
await fetch("http://localhost:5000/api/clients",{
method:"POST",
headers:{"Content-Type":"application/json"},
body:JSON.stringify(formData)
});
}

fetchClients();
setShowForm(false);
setEditId(null);

setFormData({
name:"",
co_owner:"",
phone:"",
address:"",
project:"",
floor:"",
room:"",
amount_paid:"",
payment_mode:"",
bank_name:"",
cheque_no:"",
installments:[]
});
};

// ================= DELETE =================
const handleDelete = async(id)=>{
await fetch(`http://localhost:5000/api/clients/${id}`,{method:"DELETE"});
fetchClients();
};

// ================= EDIT =================
const handleEdit = (client)=>{
setFormData({...client,installments:client.installments || []});
setEditId(client.id);
setShowForm(true);
};

// ================= SEARCH =================
const filteredClients = clients.filter(c=>
c.name.toLowerCase().includes(search.toLowerCase()) ||
c.project.toLowerCase().includes(search.toLowerCase())
);

// ================= FLOORS =================
const floors = selectedProject
? Array.from({length:selectedProject.floors},(_,i)=>i+1)
: [];

// ================= BOOKED =================
const bookedRooms = clients
.filter(c =>
c.project === formData.project &&
String(c.floor) === String(formData.floor)
)
.map(c => c.room);

return(

<div className="flex bg-gray-100 min-h-screen">

<Sidebar/>

<div className="flex-1 flex flex-col">

<Topbar/>

<div className="p-8 relative">

{/* HEADER */}
<div className="flex justify-between mb-6">
<h1 className="text-3xl font-semibold">
Client & Booking Details
</h1>

<button onClick={()=>setShowForm(true)}
className="bg-orange-500 text-white px-6 py-3 rounded-xl">
+ Add Client
</button>
</div>

{/* SEARCH */}
<input
type="text"
placeholder="Search by name or project..."
value={search}
onChange={(e)=>setSearch(e.target.value)}
className="border px-4 py-3 rounded-xl w-full mb-6"
/>

{/* ================= CLIENT LIST ================= */}
<div className="bg-white p-4 rounded-xl shadow mb-6">

  <h2 className="text-xl font-semibold mb-4">
    Clients List
  </h2>

  {clients.length === 0 ? (
    <p>No clients found</p>
  ) : (
    clients.map((client, i) => (
      <div key={client.id || i} className="border-b py-3">

        <p className="font-semibold">{client.name}</p>

        <p className="text-sm text-gray-600">
          {client.project} | Floor {client.floor} | Room {client.room}
        </p>

        <p className="text-sm">
          ₹ {client.amount_paid}
        </p>

      </div>
    ))
  )}

</div>

{/* ================= FORM (OVERLAY - FIXED) ================= */}
{showForm && (
  <div className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center z-50">

    <div className="bg-white p-8 rounded-2xl shadow w-[90%] max-w-4xl">

      <h2 className="text-xl font-semibold mb-4">
        Add Client Form
      </h2>

      <div className="grid grid-cols-2 gap-6">

        <div><label>Name</label><input name="name" value={formData.name} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>

        <div><label>Co Owner</label><input name="co_owner" value={formData.co_owner} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>

        <div><label>Phone</label><input name="phone" value={formData.phone} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>

        <div><label>Address</label><input name="address" value={formData.address} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>

        <div><label>Project</label>
          <select name="project" value={formData.project} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full">
            <option value="">-- Select Project --</option>
            {projects.map((p)=>(<option key={p.id} value={p.name}>{p.name}</option>))}
          </select>
        </div>

        <div><label>Floor</label><select name="floor" value={formData.floor} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full">
          <option value="">-- Select Floor --</option>
          {floors.map(f=>(<option key={f} value={f}>Floor {f}</option>))}
        </select></div>

        <div><label>Room</label><select name="room" value={formData.room} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full">
          <option value="">-- Select Room --</option>
          {generateRooms(formData.floor).map(room=>{
            const isBooked = bookedRooms.includes(room);
            return(<option key={room} value={room} disabled={isBooked}>{room}</option>);
          })}
        </select></div>

        <div><label>Amount Paid</label><input type="number" name="amount_paid" value={formData.amount_paid} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>

        <div><label>Payment Mode</label>
          <select name="payment_mode" value={formData.payment_mode} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full">
            <option value="">Payment Mode</option>
            <option>Cash</option>
            <option>Bank</option>
            <option>Cheque</option>
          </select>
        </div>

        {(formData.payment_mode==="Bank" || formData.payment_mode==="Cheque") && (
          <div><label>Bank Name</label><input name="bank_name" value={formData.bank_name} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>
        )}

        {formData.payment_mode==="Cheque" && (
          <div><label>Cheque No</label><input name="cheque_no" value={formData.cheque_no} onChange={handleChange} className="border px-4 py-3 rounded-xl w-full"/></div>
        )}

      </div>

      <div className="mt-6">
        <h2 className="font-semibold mb-2">Installments</h2>

        {formData.installments.map((inst,i)=>(
          <div key={i} className="flex gap-3 mb-2">
            <input type="number" value={inst.amount}
              onChange={(e)=>handleInstallmentChange(i,"amount",e.target.value)}
              className="border px-3 py-2"/>

            <input type="date"
              value={inst.date}
              onChange={(e)=>handleInstallmentChange(i,"date",e.target.value)}
              className="border px-3 py-2"/>
          </div>
        ))}

        <button onClick={addInstallment} className="bg-blue-500 text-white px-4 py-2 rounded">
          + Add Installment
        </button>
      </div>

      <div className="mt-6 flex gap-4">
        <button onClick={handleSubmit} className="bg-orange-500 text-white px-6 py-3 rounded-xl">Save</button>
        <button onClick={()=>setShowForm(false)} className="bg-gray-300 px-6 py-3 rounded-xl">Cancel</button>
      </div>

    </div>
  </div>
)}

</div>
</div>
</div>

);
}
